import React, { useEffect, useMemo, useState } from "react";
import { Link } from "react-router-dom";
import api from "../api";
import CartDrawer from "../components/CartDrawer.jsx";

// Fallback image and error handler
const FALLBACK =
  "https://images.unsplash.com/photo-1550547660-d9450f859349?w=800&auto=format&fit=crop&q=60";
const onErr = (e) => {
  e.currentTarget.src = FALLBACK;
  e.currentTarget.onerror = null;
};

// Local helpers to target public/images/veg first
function slugifyName(str = "") {
  return String(str).toLowerCase().replace(/[^a-z0-9]+/g, "-").replace(/(^-|-$)/g, "");
}

function vegLocalCandidates(name = "") {
  const slug = slugifyName(name);
  return [
    `/images/veg/${slug}.jpg`,
    `/images/veg/${slug}.jpeg`,
    `/images/veg/${slug}.png`,
    `/images/veg/${slug}.webp`,
  ];
}

function MultiSrcImage({ sources = [], alt = '', fallback, className = '', ...rest }) {
  const [idx, setIdx] = useState(0);
  const src = sources[idx] || fallback;
  return (
    <img
      src={src}
      alt={alt}
      onError={() => {
        if (idx + 1 < sources.length) setIdx(idx + 1);
        else if (fallback && src !== fallback) {
          setIdx(sources.length);
        }
      }}
      className={className}
      {...rest}
    />
  );
}

// Strictly vegetarian dishes with correct names
const VEGS = [
  { name: "Fresh Salad Bowl", price: 120, img: "data:image/jpeg;base64,"},
  { name: "Stir-fry Greens", price: 140, img: "data:image/jpeg;base64," },
  { name: "Pasta Primavera", price: 180, img: "/images/veg/pasta-primavera.jdata:image/jpeg;base64," },
  { name: "Margherita Pizza", price: 220, img: "data:image/jpeg;base64," },
  { name: "Tomato Basil Soup", price: 110, img: "data:image/jpeg;base64," },
  { name: "Avocado Toast", price: 130, img: "data:image/jpeg;base64," },
  { name: "Roasted Vegetables", price: 150, img: "data:image/jpeg;base64," },
  { name: "Veg Hakka Noodles", price: 170, img: "data:image/jpeg;base64," },
  { name: "Paneer Tikka", price: 180, img:"data:image/jpeg;base64," },
  { name: "Veg Pulao", price: 160, img: "data:image/jpeg;base64," },
  { name: "Buddha Bowl", price: 190, img: "data:image/jpeg;base64," },
  { name: "Aloo Gobi", price: 150, img: "data:image/jpeg;base64," },
  { name: "Chana Masala", price: 160, img: "https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcQERBGpqEq9d8FpvLAOjPFVM1c_Njjp4scYxA&s" },
  { name: "Palak Paneer", price: 180, img: "data:image/jpeg;base64," },
  { name: "Veg Biryani", price: 200, img: "data:image/jpeg;base64," },
  { name: "Veg Manchurian", price: 170, img: "data:image/jpeg;base64," },
  { name: "Masala Dosa", price: 120, img: "data:image/jpeg;base64," },
  { name: "Idli Sambar", price: 100, img: "data:image/jpeg;base64," }
];

export default function Veg() {
  const [cart, setCart] = useState({ items: [] });
  const [openCart, setOpenCart] = useState(false);
  const [items, setItems] = useState([]);

  useEffect(() => {
    (async () => {
      const crt = await api.get("/cart").catch(() => ({ data: { items: [] } }));
      setCart(crt.data || { items: [] });
      const res = await api.get('/items?category=veg').catch(() => ({ data: [] }));
      setItems(res.data || []);
    })();
  }, []);

  async function handleAddToCart(itemId, qty = 1) {
    try {
      await api.post('/cart', { itemId, qty });
      const crt = await api.get('/cart');
      setCart(crt.data || { items: [] });
    } catch {}
  }

  async function handleRemoveFromCart(itemId) {
    try {
      await api.delete(`/cart/${itemId}`);
      const crt = await api.get('/cart');
      setCart(crt.data || { items: [] });
    } catch {}
  }

  async function handlePlaceOrder() {
    try {
      await api.post('/orders/from-cart');
      setOpenCart(false);
      const crt = await api.get('/cart');
      setCart(crt.data || { items: [] });
      // Optionally navigate to orders page: left as simple alert
      alert('Order placed. Waiting for admin approval.');
    } catch {
      alert('Failed to place order');
    }
  }

  async function handleToggleSave(itemId) {
    try {
      await api.post(`/saved/${itemId}`);
    } catch {}
  }

  async function handleEnsureAndSave(fb) {
    try {
      const created = await api.post('/items', {
        name: fb.name,
        price: fb.price ?? 0,
        image: fb.img,
        categorySlug: 'veg'
      });
      const id = created?.data?._id;
      if (id) await handleToggleSave(id);
    } catch {}
  }

  async function handleEnsureAndAdd(fb) {
    try {
      const created = await api.post('/items', {
        name: fb.name,
        price: fb.price ?? 0,
        image: fb.img,
        categorySlug: 'veg'
      });
      const id = created?.data?._id;
      if (id) {
        await handleAddToCart(id, 1);
      }
    } catch {}
  }

  const total = useMemo(() => {
    return (cart.items || []).reduce((sum, item) => {
      const price = item.itemId?.price ?? 0;
      const qty = item.qty ?? 0;
      return sum + price * qty;
    }, 0);
  }, [cart.items]);

  // Build a combined list: prefer API items, and top up with fallback VEGS so the grid looks full
  const combined = useMemo(() => {
    const apiItems = Array.isArray(items) ? items : [];
    if (apiItems.length === 0) {
      return { api: [], fallback: VEGS };
    }
    const desired = 12; // target count to make the grid look filled
    const needed = Math.max(0, desired - apiItems.length);
    return { api: apiItems, fallback: VEGS.slice(0, needed) };
  }, [items]);

  return (
    <div className="min-h-screen bg-blue-50">
      <div className="max-w-6xl mx-auto p-4 sm:p-6">
        {/* Orange bordered header */}
        <div className="grid grid-cols-3 items-center gap-4 mb-5">
          <div className="justify-self-start">
            <Link to="/home" className="inline-flex items-center gap-2 px-5 py-2.5 text-base font-medium border rounded-md bg-gray-100 text-gray-700 hover:bg-gray-200">← Back</Link>
          </div>
          <div className="justify-self-center w-full max-w-xl mx-2">
            <div className="border-2 border-orange-500 rounded-lg bg-white">
              <h1 className="text-3xl font-extrabold text-orange-600 text-center py-2">Veg Varieties</h1>
            </div>
          </div>
          <div className="justify-self-end">
            <button
              onClick={() => setOpenCart(true)}
              className="flex items-center gap-2 px-4 py-2 bg-[#ffad33] text-white rounded-lg hover:bg-[#ffa31a] transition-colors border border-[#ffad33]"
            >
              Cart
              {(cart.items?.length ?? 0) > 0 && (
                <span className="ml-1 bg-red-500 text-white text-xs rounded-full h-5 w-5 flex items-center justify-center">
                  {cart.items.length}
                </span>
              )}
            </button>
          </div>
        </div>

        {/* Grid: render ONLY local VEGS to guarantee public images show */}
        <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-6">
          {VEGS.map((it, i) => (
            <div key={`veg-${i}`} className="bg-white rounded-xl shadow-sm border border-[#ffad33] hover:shadow-md transition-shadow overflow-hidden">
              <div className="aspect-video rounded-t-xl overflow-hidden">
                <MultiSrcImage
                  sources={[...vegLocalCandidates(it.name), ...(it.img ? [it.img] : [])]}
                  fallback={FALLBACK}
                  alt={it.name}
                  className="w-full h-full object-cover"
                  referrerPolicy="no-referrer"
                />
              </div>
              <div className="p-3">
                <div className="font-semibold text-gray-900">{it.name}</div>
                {it.price != null && <div className="text-sm text-gray-600">₹{it.price}</div>}
                <div className="mt-3 flex gap-2">
                  <button className="px-3 py-2 bg-[#ffad33] text-white rounded hover:bg-[#ffa31a]" onClick={() => handleEnsureAndAdd(it)}>Add to Cart</button>
                  <button className="px-3 py-2 border border-[#ffad33] text-[#ffad33] rounded hover:bg-[#ffad33]/10" onClick={() => handleEnsureAndSave(it)}>Save</button>
                </div>
              </div>
            </div>
          ))}
        </div>

        <CartDrawer open={openCart} onClose={() => setOpenCart(false)} items={cart.items || []} total={total} onRemove={handleRemoveFromCart} onPlaceOrder={handlePlaceOrder} />
      </div>
    </div>
  );
}